import{_ as l,o as a,c as i,ae as r}from"./chunks/framework.BD9pLfSD.js";const c=JSON.parse('{"title":"数据隐私问题","description":"","frontmatter":{},"headers":[],"relativePath":"1-FAQ/4-data-privacy.md","filePath":"1-FAQ/4-data-privacy.md"}'),o={name:"1-FAQ/4-data-privacy.md"};function e(n,t,d,s,h,p){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="数据隐私问题" tabindex="-1">数据隐私问题 <a class="header-anchor" href="#数据隐私问题" aria-label="Permalink to &quot;数据隐私问题&quot;">​</a></h1><h2 id="数据收集" tabindex="-1">数据收集 <a class="header-anchor" href="#数据收集" aria-label="Permalink to &quot;数据收集&quot;">​</a></h2><h3 id="q1-平台收集哪些数据" tabindex="-1">Q1: 平台收集哪些数据？ <a class="header-anchor" href="#q1-平台收集哪些数据" aria-label="Permalink to &quot;Q1: 平台收集哪些数据？&quot;">​</a></h3><p><strong>A</strong>: CogniAND平台收集以下类型的数据：</p><p><strong>账户信息：</strong></p><ul><li>邮箱地址、姓名、性别、出生日期</li><li>用户角色（被试/实验者）</li></ul><p><strong>实验数据：</strong></p><ul><li>实验反应时间、选择和判断结果</li><li>任务完成情况、实验进度记录</li></ul><p><strong>使用数据：</strong></p><ul><li>登录时间和频率、平台使用行为</li><li>实验参与记录、系统交互日志</li></ul><p>我们遵循<strong>数据最小化原则</strong>，只收集必要的数据，不收集与实验无关的个人信息。</p><h3 id="q2-数据会保留多久" tabindex="-1">Q2: 数据会保留多久？ <a class="header-anchor" href="#q2-数据会保留多久" aria-label="Permalink to &quot;Q2: 数据会保留多久？&quot;">​</a></h3><p><strong>A</strong>: 不同类型数据的保留期限：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>保留期限</th></tr></thead><tbody><tr><td>账户数据</td><td>账户存续期间</td></tr><tr><td>实验数据</td><td>根据研究要求（通常5-10年）</td></tr><tr><td>使用日志</td><td>6个月</td></tr><tr><td>已删除账户数据</td><td>30天内彻底删除</td></tr></tbody></table><h2 id="隐私保护" tabindex="-1">隐私保护 <a class="header-anchor" href="#隐私保护" aria-label="Permalink to &quot;隐私保护&quot;">​</a></h2><h3 id="q3-平台如何保护我的隐私" tabindex="-1">Q3: 平台如何保护我的隐私？ <a class="header-anchor" href="#q3-平台如何保护我的隐私" aria-label="Permalink to &quot;Q3: 平台如何保护我的隐私？&quot;">​</a></h3><p><strong>A</strong>: 我们采用多重保护措施：</p><ol><li><p><strong>数据匿名化</strong></p><ul><li>实验数据使用唯一ID标识</li><li>不关联个人身份信息</li><li>数据导出自动匿名化</li></ul></li><li><p><strong>访问控制</strong></p><ul><li>严格的权限管理</li><li>安全的数据存储</li><li>限制数据使用范围</li></ul></li><li><p><strong>用户控制</strong></p><ul><li>设置隐私偏好</li><li>控制数据共享范围</li><li>随时删除账户</li></ul></li></ol><h3 id="q4-我的数据会被分享给第三方吗" tabindex="-1">Q4: 我的数据会被分享给第三方吗？ <a class="header-anchor" href="#q4-我的数据会被分享给第三方吗" aria-label="Permalink to &quot;Q4: 我的数据会被分享给第三方吗？&quot;">​</a></h3><p><strong>A</strong>: 我们<strong>不会出售、出租或交易</strong>您的个人信息。仅在以下情况下共享数据：</p><ul><li>✅ 获得您的明确同意</li><li>✅ 法律法规要求</li><li>✅ 学术合作（匿名化数据）</li><li>✅ 服务提供商（受保密协议约束）</li></ul><p>我们使用的第三方服务（邮件服务、云存储、分析工具）均签署数据保护协议。</p><h2 id="知情同意" tabindex="-1">知情同意 <a class="header-anchor" href="#知情同意" aria-label="Permalink to &quot;知情同意&quot;">​</a></h2><h3 id="q5-什么是知情同意-为什么重要" tabindex="-1">Q5: 什么是知情同意？为什么重要？ <a class="header-anchor" href="#q5-什么是知情同意-为什么重要" aria-label="Permalink to &quot;Q5: 什么是知情同意？为什么重要？&quot;">​</a></h3><p><strong>A</strong>: 知情同意是参与实验前的重要环节，确保您充分了解实验内容并自愿参与。</p><p><strong>知情同意包含：</strong></p><ul><li>实验信息（目的、流程、时长、要求）</li><li>数据使用（收集类型、使用方式、保存期限）</li><li>参与者权利（自愿参与、随时退出、数据访问）</li><li>风险和收益（可能的不适、潜在收益、补偿说明）</li><li>联系方式（研究者、伦理委员会、投诉渠道）</li></ul><p><strong>知情同意流程：</strong></p><ol><li>阅读知情同意书</li><li>确认同意</li><li>开始实验</li></ol><h3 id="q6-同意后可以撤回吗" tabindex="-1">Q6: 同意后可以撤回吗？ <a class="header-anchor" href="#q6-同意后可以撤回吗" aria-label="Permalink to &quot;Q6: 同意后可以撤回吗？&quot;">​</a></h3><p><strong>A</strong>: 可以，您有权随时撤回同意：</p><ul><li>✅ 退出正在进行的实验</li><li>✅ 要求删除已收集的数据</li><li>⚠️ 不影响已完成的实验数据（已用于研究）</li></ul><p><strong>如何撤回：</strong></p><ul><li>在实验界面点击&quot;退出实验&quot;</li><li>联系研究者或平台管理员</li><li>通过<a href="/7-technical-support/1-contact.html">技术支持</a>提交申请</li></ul><h2 id="伦理规范" tabindex="-1">伦理规范 <a class="header-anchor" href="#伦理规范" aria-label="Permalink to &quot;伦理规范&quot;">​</a></h2><h3 id="q7-平台遵循哪些伦理原则" tabindex="-1">Q7: 平台遵循哪些伦理原则？ <a class="header-anchor" href="#q7-平台遵循哪些伦理原则" aria-label="Permalink to &quot;Q7: 平台遵循哪些伦理原则？&quot;">​</a></h3><p><strong>A</strong>: CogniAND平台严格遵守心理学研究伦理规范：</p><ol><li><p><strong>尊重原则</strong></p><ul><li>尊重参与者的自主权和隐私</li><li>尊重文化差异，平等对待所有参与者</li></ul></li><li><p><strong>有利原则</strong></p><ul><li>最大化研究收益，最小化潜在风险</li><li>提供必要的支持，分享研究成果</li></ul></li><li><p><strong>公正原则</strong></p><ul><li>公平选择参与者，合理分配研究负担和收益</li><li>避免歧视和偏见，保障弱势群体权益</li></ul></li><li><p><strong>诚信原则</strong></p><ul><li>真实报告研究结果，避免学术不端行为</li><li>保持研究透明度，负责任地使用数据</li></ul></li></ol><h2 id="用户权利" tabindex="-1">用户权利 <a class="header-anchor" href="#用户权利" aria-label="Permalink to &quot;用户权利&quot;">​</a></h2><h3 id="q8-我有哪些数据权利" tabindex="-1">Q8: 我有哪些数据权利？ <a class="header-anchor" href="#q8-我有哪些数据权利" aria-label="Permalink to &quot;Q8: 我有哪些数据权利？&quot;">​</a></h3><p><strong>A</strong>: 您享有以下数据权利：</p><table tabindex="0"><thead><tr><th>权利</th><th>说明</th></tr></thead><tbody><tr><td>✅ 数据访问权</td><td>查看自己的数据</td></tr><tr><td>✅ 数据修改权</td><td>修改个人信息</td></tr><tr><td>✅ 数据删除权</td><td>申请删除账户</td></tr><tr><td>✅ 数据导出权</td><td>导出自己的数据</td></tr><tr><td>✅ 拒绝权</td><td>拒绝特定数据收集</td></tr><tr><td>✅ 撤回权</td><td>撤回知情同意</td></tr></tbody></table><p><strong>如何行使权利：</strong></p><ul><li>登录个人中心查看和修改数据</li><li>联系<a href="/7-technical-support/1-contact.html">技术支持</a>申请删除或导出</li><li>在实验界面撤回同意</li></ul><p>详细说明：<a href="/5-data-privacy/">数据与隐私</a></p><h3 id="q9-如何删除我的数据" tabindex="-1">Q9: 如何删除我的数据？ <a class="header-anchor" href="#q9-如何删除我的数据" aria-label="Permalink to &quot;Q9: 如何删除我的数据？&quot;">​</a></h3><p><strong>A</strong>: 您可以通过以下方式删除数据：</p><p><strong>删除账户：</strong></p><ol><li>联系平台管理员申请删除账户</li><li>提供账户信息进行身份验证</li><li>确认删除操作（不可撤销）</li><li>30天内彻底删除所有个人数据</li></ol><p><strong>删除实验数据：</strong></p><ul><li>在实验进行中可随时退出并要求删除数据</li><li>已完成的实验数据可能因研究需要保留（匿名化处理）</li></ul><p><strong>重要提示：</strong></p><ul><li>⚠️ 删除操作不可撤销，请谨慎操作</li><li>⚠️ 已用于科学研究的匿名化数据可能无法删除</li><li>⚠️ 删除账户后无法恢复</li></ul><p>联系方式：<a href="/7-technical-support/1-contact.html">技术支持</a></p><hr>',55)])])}const g=l(o,[["render",e]]);export{c as __pageData,g as default};
